@using sv_f62874d9c03645d5aa6efb775a46cc1c.Models

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="step-list d-flex justify-content-between list-unstyled mb-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var status = GetStepStatus(step);
            <li class="step-item @status" @onclick="() => HandleStepClick(step)" role="button"
                aria-current="@(step == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (CompletedSteps.Contains(step))
                    {
                        <span class="step-check">&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "future";
    }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    padding: 1rem 0;
}

.step-list {
    counter-reset: step;
    position: relative;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    text-align: center;
}

.step-item:not(:last-child)::after {
    content: '';
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-item.active:not(:last-child)::after {
    background: linear-gradient(to right, #0d6efd 50%, #dee2e6 50%);
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    z-index: 1;
    background-color: #dee2e6;
    color: #6c757d;
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
    cursor: pointer;
}

.step-check {
    font-size: 1rem;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: #6c757d;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

