@using sv_f62874d9c03645d5aa6efb775a46cc1c.Models

<h5 class="mb-3">Personal Information</h5>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(HasError("FullName") ? "is-invalid" : "")"
            @bind="Model.FullName" @bind:event="oninput" />
        @if (HasError("FullName"))
        {
            <div class="invalid-feedback">Full name is required.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(HasError("Email") ? "is-invalid" : "")"
            @bind="Model.Email" @bind:event="oninput" />
        @if (HasError("Email"))
        {
            <div class="invalid-feedback">@GetError("Email")</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control @(HasError("Phone") ? "is-invalid" : "")"
            @bind="Model.Phone" @bind:event="oninput" />
        @if (HasError("Phone"))
        {
            <div class="invalid-feedback">Phone is required.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control @(HasError("Address") ? "is-invalid" : "")"
            @bind="Model.Address" @bind:event="oninput" />
        @if (HasError("Address"))
        {
            <div class="invalid-feedback">Address is required.</div>
        }
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private string? ErrorMessage;
    private bool IsValidating;

    private bool HasError(string field) => _errors.ContainsKey(field);
    private string GetError(string field) => _errors.GetValueOrDefault(field, "");

    private async Task HandleNext()
    {
        _errors.Clear();
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName)) _errors["FullName"] = "required";
        if (string.IsNullOrWhiteSpace(Model.Email)) _errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone)) _errors["Phone"] = "required";
        if (string.IsNullOrWhiteSpace(Model.Address)) _errors["Address"] = "required";

        if (_errors.Count > 0) return;

        IsValidating = true;
        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                _errors["Email"] = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        catch
        {
            ErrorMessage = "Email validation failed. Please try again.";
        }
        finally
        {
            IsValidating = false;
        }
    }
}

