@using sv_f62874d9c03645d5aa6efb775a46cc1c.Models

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h3 class="mb-4">Job Application</h3>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-3">
        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personal"
                                  ValidateEmail="ValidateEmail"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="_references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="_coverLetter"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="_personal"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="_coverLetter"
                            OnBack="PreviousStep"
                            OnEditSection="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();

    // Form state
    private readonly PersonalInfoModel _personal = new();
    private List<WorkEntryModel> _workEntries = [new WorkEntryModel()];
    private List<ReferenceModel> _references = [new ReferenceModel(), new ReferenceModel()];
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep++;
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private Task<bool> ValidateEmail(string email)
    {
        return ApplicationService.ValidateEmailAsync(email);
    }

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            _personal.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

