toolArgs.file_text:
.step-indicator {
    padding: 1rem 0;
}

.step-list {
    counter-reset: step;
    position: relative;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    text-align: center;
}

.step-item:not(:last-child)::after {
    content: '';
    position: absolute;
    top: 18px;
    left: calc(50% + 20px);
    width: calc(100% - 40px);
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-item.active:not(:last-child)::after {
    background: linear-gradient(to right, #0d6efd 50%, #dee2e6 50%);
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    z-index: 1;
    background-color: #dee2e6;
    color: #6c757d;
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: #fff;
    cursor: pointer;
}

.step-check {
    font-size: 1rem;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: #6c757d;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
    cursor: pointer;
}

