toolArgs.file_text:
@using sv_f62874d9c03645d5aa6efb775a46cc1c.Models

<h5 class="mb-4">Review Your Application</h5>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success text-center py-4">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>.</p>
        <p class="mt-2 text-muted">We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <div style="white-space: pre-wrap;">@CoverLetter</div>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            SubmittedId = await OnSubmit();
        }
        catch
        {
            ErrorMessage = "Submission failed. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@page "/apply"
@rendermode InteractiveServer
@using sv_f62874d9c03645d5aa6efb775a46cc1c.Models

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h3 class="mb-4">Job Application</h3>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-3">
        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personal"
                                  ValidateEmail="ValidateEmail"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="_references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="_coverLetter"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="_personal"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="_coverLetter"
                            OnBack="PreviousStep"
                            OnEditSection="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();

    // Form state
    private readonly PersonalInfoModel _personal = new();
    private List<WorkEntryModel> _workEntries = [new WorkEntryModel()];
    private List<ReferenceModel> _references = [new ReferenceModel(), new ReferenceModel()];
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep++;
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private Task<bool> ValidateEmail(string email)
    {
        return ApplicationService.ValidateEmailAsync(email);
    }

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            _personal.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

